594: 	requestCounter.WithContext(req.Context()).WithLabelValues(reportedVerb, dryRun, group, version, resource, subresource, scope, component, codeToString(httpCode)).Inc()
595: 	// MonitorRequest happens after authentication, so we can trust the username given by the request
596: 	info, ok := request.UserFrom(req.Context())
